document.addEventListener("DOMContentLoaded",function(){const e=document.querySelectorAll(".auto-close");setTimeout(function(){e.forEach(function(e){!function fadeAndSlide(e){let t=1;const n=setInterval(function(){if(t>0)t-=.1,e.style.opacity=t;else{clearInterval(n);let t=e.offsetHeight;const o=setInterval(function(){t>0?(t-=10,e.style.height=t+"px"):(clearInterval(o),e.parentNode&&e.parentNode.removeChild(e))},50)}},50)}(e)})},4e3)});